tinymce.PluginManager.add('quote', function(editor, url) {
    //  editor.ui.registry.addIcon('stream', '<svg class="icon"><use xlink:href="../../svg/custom-icons.svg#stream"></use></svg>');
    // editor.ui.registry.addIcon('stream', '<svg width="24" height="24"><use xlink:href="../../tinymce/svg/custom-icons.svg#stream"></use></svg>');
    editor.ui.registry.addIcon('quote', '<?xml version="1.0" encoding="UTF-8"?>\n' +
        '<svg width="24px" height="24px" viewBox="0 0 24 24" version="1.1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">\n' +
        '    <defs></defs>\n' +
        '    <g stroke="none" stroke-width="1" fill="none" fill-rule="evenodd">\n' +
        '        <path d="M7.5,17 L8.38196601,17 C8.76073807,17 9.10700119,16.7859976 9.2763932,16.4472136 L11,13 L11,8 C11,7.44771525 10.5522847,7 10,7 L6,7 C5.44771525,7 5,7.44771525 5,8 L5,12 C5,12.5522847 5.44771525,13 6,13 L8,13 L6.67082039,15.6583592 C6.44184877,16.1163025 6.62746694,16.673157 7.0854102,16.9021286 C7.21413626,16.9664917 7.35607988,17 7.5,17 Z M15.5,17 L16.381966,17 C16.7607381,17 17.1070012,16.7859976 17.2763932,16.4472136 L19,13 L19,8 C19,7.44771525 18.5522847,7 18,7 L14,7 C13.4477153,7 13,7.44771525 13,8 L13,12 C13,12.5522847 13.4477153,13 14,13 L16,13 L14.6708204,15.6583592 C14.4418488,16.1163025 14.6274669,16.673157 15.0854102,16.9021286 C15.2141363,16.9664917 15.3560799,17 15.5,17 Z" fill="#000000" fill-rule="nonzero"></path>\n' +
        '    </g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
        return editor.windowManager.openUrl({
            url: tinymce.baseURL + '/plugins/quote/scripts/quote.php'+query,
            title: 'Quote',
            width: 400,
            height: 410,

        });

    };


    editor.ui.registry.addButton('quote', {
        tooltip: 'Quote',
        icon: 'quote',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('quote', {
        text: 'Quote',
        icon: 'quote',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});